package raw

import (
	"context"
	"testing"

	"github.com/ethereum/go-ethereum/common"
	"github.com/google/go-cmp/cmp"

	"github.com/gobitfly/beaconchain/pkg/commons/db2/database"
	"github.com/gobitfly/beaconchain/pkg/commons/db2/database/databasetest"
)

func TestRaw(t *testing.T) {
	client, admin := databasetest.NewBigTable(t)

	s, err := database.NewBigTableWithClient(context.Background(), client, admin, Schema)
	if err != nil {
		t.Fatal(err)
	}

	store := Store{
		db:         database.Wrap(s, Table),
		compressor: noOpCompressor{},
	}

	tests := []struct {
		name  string
		block FullBlockData
	}{
		{
			name:  "test block",
			block: testFullBlock,
		},
		{
			name:  "two uncles",
			block: testTwoUnclesFullBlock,
		},
		{
			name:  "arbitrum",
			block: testArbFullBlock,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if err := store.AddBlocks([]FullBlockData{tt.block}); err != nil {
				t.Fatal(err)
			}

			res, err := store.ReadBlockByNumber(tt.block.ChainID, tt.block.BlockNumber)
			if err != nil {
				t.Fatal(err)
			}

			if diff := cmp.Diff(string(res.Block), string(tt.block.Block)); diff != "" {
				t.Errorf("block mismatch (-want +got):\n%s", diff)
			}
			if diff := cmp.Diff(string(res.Receipts), string(tt.block.Receipts)); diff != "" {
				t.Errorf("receipts mismatch (-want +got):\n%s", diff)
			}
			if diff := cmp.Diff(string(res.Traces), string(tt.block.Traces)); diff != "" {
				t.Errorf("traces mismatch (-want +got):\n%s", diff)
			}
			if diff := cmp.Diff(string(res.Uncles), string(tt.block.Uncles)); diff != "" {
				t.Errorf("uncles mismatch (-want +got):\n%s", diff)
			}
		})
	}
}

var testFullBlock = FullBlockData{
	ChainID:          1,
	BlockNumber:      testBlockNumber,
	BlockHash:        common.HexToHash(testBlockHash).Bytes(),
	BlockUnclesCount: 1,
	Block:            []byte(testBlock),
	Receipts:         []byte(testReceipts),
	Traces:           []byte(testTraces),
	Uncles:           []byte(testUncles),
}

var testTwoUnclesFullBlock = FullBlockData{
	ChainID:          1,
	BlockNumber:      testTwoUnclesBlockNumber,
	BlockUnclesCount: 2,
	Block:            []byte(testTwoUnclesBlock),
	Receipts:         nil,
	Traces:           nil,
	Uncles:           []byte(testTwoUnclesBlockUncles),
}

